class Chunk{constructor(data=[],size=10){try{this.validateChunk(data);this.data=data;this.size=size;this.chunkedData=this.getChunkData()}catch(e){const res=e.response;if(res){this.notify(res.data,"error")}else{this.notify(e.message,"error")}return null}}validateChunk(data){if(data.length<=0){throw new Error("Chunk data cannot be empty")}}getChunkData(){const totalChunks=Math.ceil(this.data.length/this.size);let chunkedData=[];for(let i=0;i<totalChunks;i++){const start=i*this.size;const end=Math.min(start+this.size,this.data.length);const chunk=this.data.slice(start,end);chunkedData.push(chunk)}return chunkedData}chunkArray(property){const chunked=[];this.data.forEach((item=>{const{[property]:logs,...rest}=item;if(Array.isArray(logs)){for(let i=0;i<logs.length;i+=this.size){const chunk=logs.slice(i,i+this.size);chunked.push({...rest,[property]:chunk})}}}));return chunked}notify(message,type){console.error(`${type.toUpperCase()}: ${message}`)}}